B.bws=new A.o_("Problem","\ubb38\uc81c \uc815\uc758","\uc678\uc8fc \uac1c\ubc1c \ud50c\ub7ab\ud3fc\uc5d0\ub294 \ub9e4\uc77c \uc5ec\ub7ec \uc2e0\uaddc \ud504\ub85c\uc81d\ud2b8\uac00 \uc62c\ub77c\uc635\ub2c8\ub2e4. \uc0ac\ub78c\uc774 \uc9c1\uc811 \uacf5\uace0\ub97c \uc77d\uace0, \ud68c\uc0ac \uc5ed\ub7c9\uacfc \ub9de\ub294\uc9c0 \ud310\ub2e8\ud558\uace0, \uc81c\uc548\uc11c\uc640 \uc0ac\uc804 \uc9c8\ubb38 \ub2f5\ubcc0\uc744 \uc791\uc131\ud558\uace0, \uad00\ub828 \ud3ec\ud2b8\ud3f4\ub9ac\uc624\ub97c \uace0\ub978 \ub4a4 \uc81c\ucd9c\uacfc \ub313\uae00, \uc751\ub2f5 \ucd94\uc801\uae4c\uc9c0 \ucc98\ub9ac\ud558\uba74 \ud55c \uac74\ub9c8\ub2e4 \ubc18\ubcf5 \uc2dc\uac04\uc774 \ud06c\uac8c \ubc1c\uc0dd\ud569\ub2c8\ub2e4.\n\n\uc774 \ud504\ub85c\uc81d\ud2b8\ub294 \ub2e8\uc21c \uc785\ub825 \uc790\ub3d9\ud654\uac00 \uc544\ub2c8\ub77c, \uc0ac\ub78c\uc774 \uc704\uc2dc\ucf13\uc5d0\uc11c \uad00\uc2ec \ud45c\uc2dc\ud55c \ud504\ub85c\uc81d\ud2b8\ub97c \uae30\uc900\uc73c\ub85c \ubcf8\ubb38 \ucd94\ucd9c, \uc81c\uc548\uc11c \uc0dd\uc131, \ubbfc\uac10 \uc815\ubcf4 \ub9c8\uc2a4\ud0b9, \uc790\ub3d9 \uc81c\ucd9c, \ube44\uacf5\uac1c \ub313\uae00 \uc791\uc131, \uc0c1\ud0dc \ucd94\uc801, \ubaa8\ubc14\uc77c \ubcf4\ub4dc \ub3d9\uae30\ud654\uae4c\uc9c0 \uc774\uc5b4\uc9c0\ub294 \uc5c5\ubb34 \ud750\ub984\uc744 \uc81c\ud488\ucc98\ub7fc \uc7ac\uc124\uacc4\ud55c \uc0ac\ub840\uc785\ub2c8\ub2e4.",B.bB,null)
B.bwC=new A.o_("Positioning","\ud480\uc2a4\ud0dd \ud750\ub984\uc744 \uc774\ud574\ud55c \uc790\ub3d9\ud654","\uc774 \uc0ac\ub840\uc5d0\uc11c Flutter\ub294 \ud575\uc2ec \uc694\uad6c\uc0ac\ud56d\uc774 \uc544\ub2c8\uc5c8\uc2b5\ub2c8\ub2e4. \uc911\uc694\ud55c \uac83\uc740 \uc0ac\uc6a9\uc790\uac00 \ubcf4\ub294 \ud654\uba74, \ubc31\uc5d4\ub4dc API, \ub85c\uceec/\ud074\ub77c\uc6b0\ub4dc DB \uc0c1\ud0dc, \ube0c\ub77c\uc6b0\uc800 \uc790\ub3d9\ud654, \ud478\uc2dc \uc54c\ub9bc, \ubc30\ud3ec\ub41c \ub300\uc2dc\ubcf4\ub4dc\uac00 \uc11c\ub85c \uc5b4\uae0b\ub098\uc9c0 \uc54a\ub3c4\ub85d \uc804\uccb4 \ud750\ub984\uc744 \uc774\ud574\ud558\uace0 \uc124\uacc4\ud558\ub294 \uc77c\uc774\uc5c8\uc2b5\ub2c8\ub2e4.\n\n\uc571 \uac1c\ubc1c \uacbd\ud5d8\uc73c\ub85c \uc0ac\uc6a9\uc790 \ud750\ub984\uacfc \uc608\uc678 \uc0c1\ud0dc\ub97c \ube60\ub974\uac8c \uc7a1\uace0, Django \ubc31\uc5d4\ub4dc \uc2e4\ubb34 \uacbd\ud5d8\uacfc \ud604\uc7ac Node.js \ubc31\uc5d4\ub4dc \uac1c\ubc1c \uacbd\ud5d8\uc744 \ubc14\ud0d5\uc73c\ub85c API \uacc4\uc57d, DB \ub3d9\uae30\ud654, \uc6b4\uc601 \uc790\ub3d9\ud654\uc758 \uc2e4\ud328 \uc9c0\uc810\uc744 \ud568\uaed8 \ubcf4\uba70 \uc2dc\uc2a4\ud15c\uc744 \uad6c\uc131\ud588\uc2b5\ub2c8\ub2e4.",B.bB,null)
